const DEBUG = $env.DEBUG === 'true';
const log   = (...args) => { if (DEBUG) console.log(...args); };

const body = $input.first().json.body;

let payload;
try {
  const decoded = decodeURIComponent(body.payload ?? '{}');
  payload = JSON.parse(decoded);
} catch(e) {
  throw new Error('Could not parse Slack payload: ' + e.message);
}

const actionId  = payload.actions?.[0]?.action_id ?? 'unknown';
const actionVal = payload.actions?.[0]?.value      ?? '';
const userName  = payload.user?.name               ?? 'unknown';
const approved  = actionId === 'approve_brief';

log('Action:', actionId, 'by', userName);

return [{
  json: {
    actionId,
    actionVal,
    userName,
    approved,
    docUrl:    actionVal.startsWith('http') ? actionVal : '',
    clickedAt: new Date().toISOString()
  }
}];

const DEBUG = $env.DEBUG === 'true';
const log   = (...args) => { if (DEBUG) console.log(...args); };

// ── S-01 Fix: Slack Request Signature Verification ──────────────────────
const crypto = require('crypto');

const item = $input.first();

// ── 1. Extract required headers ─────────────────────────────────────────
const slackSignature = item.json.headers?.['x-slack-signature'];
const slackTimestamp = item.json.headers?.['x-slack-request-timestamp'];
const rawBody        = item.json.rawBody;

// ── 2. Guard: reject if any required value is missing ───────────────────
if (!slackSignature || !slackTimestamp || !rawBody) {
  throw new Error(
    'SECURITY REJECT: Missing Slack verification headers. ' +
    'Signature present: ' + !!slackSignature + ', ' +
    'Timestamp present: ' + !!slackTimestamp + ', ' +
    'Raw body present: '  + !!rawBody
  );
}

// ── 3. Replay attack check ───────────────────────────────────────────────
const nowSeconds       = Math.floor(Date.now() / 1000);
const timestampSeconds = parseInt(slackTimestamp, 10);

if (isNaN(timestampSeconds)) {
  throw new Error(
    'SECURITY REJECT: x-slack-request-timestamp is not a valid integer. ' +
    'Received: ' + slackTimestamp
  );
}

const ageSecs = Math.abs(nowSeconds - timestampSeconds);
if (ageSecs > 300) {
  throw new Error(
    'SECURITY REJECT: Request is ' + ageSecs + 's old. ' +
    'Max allowed is 300s. Possible replay attack.'
  );
}

// ── 4. Read signing secret from environment variable ────────────────────
const signingSecret = $env.SLACK_SIGNING_SECRET;

if (!signingSecret) {
  throw new Error(
    'CONFIG ERROR: SLACK_SIGNING_SECRET environment variable is not set. ' +
    'Add it in n8n Settings → Environment Variables.'
  );
}

// ── 5. Build the signature base string ──────────────────────────────────
const baseString = `v0:${slackTimestamp}:${rawBody}`;

// ── 6. Compute HMAC-SHA256 ───────────────────────────────────────────────
const mySignature = 'v0=' + crypto
  .createHmac('sha256', signingSecret)
  .update(baseString, 'utf8')
  .digest('hex');

// ── 7. Constant-time comparison to prevent timing attacks ────────────────
const sigBuffer = Buffer.from(mySignature,    'utf8');
const slackBuf  = Buffer.from(slackSignature, 'utf8');

const lengthsMatch = sigBuffer.length === slackBuf.length;

const safeA = Buffer.alloc(Math.max(sigBuffer.length, slackBuf.length));
const safeB = Buffer.alloc(Math.max(sigBuffer.length, slackBuf.length));
sigBuffer.copy(safeA);
slackBuf.copy(safeB);

const signaturesMatch = lengthsMatch && crypto.timingSafeEqual(safeA, safeB);

if (!signaturesMatch) {
  throw new Error(
    'SECURITY REJECT: Slack signature mismatch. ' +
    'Expected: ' + mySignature + ' | ' +
    'Received: ' + slackSignature
  );
}

// ── 8. Verification passed — pass item through unchanged ─────────────────
log('Slack signature verified OK. Request age: ' + ageSecs + 's');
return $input.all();
